import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule, ReactiveFormsModule, FormBuilder, FormGroup, Validators, FormArray } from '@angular/forms';
import { TaxReturnService } from '../../services/tax-return.service';
import { TaxReturn, ValidationResult } from '../../models/tax-return.model';

@Component({
  selector: 'app-tax-return-form',
  standalone: true,
  imports: [CommonModule, FormsModule, ReactiveFormsModule],
  templateUrl: './tax-return-form.component.html',
  styleUrls: ['./tax-return-form.component.scss']
})
export class TaxReturnFormComponent {
  taxForm: FormGroup;
  validationResult: ValidationResult | null = null;
  loading = false;
  error: string | null = null;

  constructor(private fb: FormBuilder, private taxService: TaxReturnService) {
    this.taxForm = this.fb.group({
      taxpayerId: ['', Validators.required],
      taxYear: [2023, [Validators.required, Validators.min(2000), Validators.max(2025)]],
      filingStatus: ['Single', Validators.required],
      totalIncome: [0, Validators.required],
      totalDeductions: [0],
      taxableIncome: [0],
      totalTax: [0],
      withholdingAmount: [0],
      hasDependents: [false],
      numberOfDependents: [0],
      form1040: this.fb.group({
        name: ['', Validators.required],
        ssn: ['', Validators.required],
        address: [''],
        line1_Wages: [0],
        line2_Interest: [0],
        line3_Dividends: [0],
        line8_TotalIncome: [0]
      }),
      scheduleA: this.fb.group({
        medicalExpenses: [0],
        stateAndLocalTaxes: [0],
        mortgageInterest: [0],
        charitableContributions: [0],
        totalItemizedDeductions: [0]
      }),
      scheduleC: this.fb.group({
        businessName: [''],
        grossReceipts: [0],
        totalExpenses: [0],
        netProfit: [0]
      }),
      w2Forms: this.fb.array([])
    });
  }

  get w2Forms() {
    return this.taxForm.get('w2Forms') as FormArray;
  }

  addW2Form() {
    const w2Form = this.fb.group({
      employerName: ['', Validators.required],
      employerEIN: ['', Validators.required],
      wages: [0, Validators.required],
      federalTaxWithheld: [0],
      socialSecurityWages: [0]
    });
    this.w2Forms.push(w2Form);
  }

  removeW2Form(index: number) {
    this.w2Forms.removeAt(index);
  }

  onSubmit() {
    if (this.taxForm.valid) {
      this.loading = true;
      this.error = null;
      this.validationResult = null;

      const taxReturn: TaxReturn = this.taxForm.value;
      
      this.taxService.validateTaxReturn(taxReturn).subscribe({
        next: (result) => {
          this.validationResult = result;
          this.loading = false;
        },
        error: (err) => {
          this.error = 'An error occurred while validating the tax return.';
          this.loading = false;
          console.error(err);
        }
      });
    } else {
      this.taxForm.markAllAsTouched();
    }
  }
}
<div class="container mt-4">
  <h2>Tax Return Data Input</h2>
  <form [formGroup]="taxForm" (ngSubmit)="onSubmit()">
    <div class="card mb-3">
      <div class="card-header">Basic Information</div>
      <div class="card-body">
        <div class="row">
          <div class="col-md-4 mb-3">
            <label class="form-label">Taxpayer ID</label>
            <input type="text" class="form-control" formControlName="taxpayerId">
          </div>
          <div class="col-md-4 mb-3">
            <label class="form-label">Tax Year</label>
            <input type="number" class="form-control" formControlName="taxYear">
          </div>
          <div class="col-md-4 mb-3">
            <label class="form-label">Filing Status</label>
            <select class="form-select" formControlName="filingStatus">
              <option value="Single">Single</option>
              <option value="MarriedFilingJointly">Married Filing Jointly</option>
              <option value="MarriedFilingSeparately">Married Filing Separately</option>
              <option value="HeadOfHousehold">Head of Household</option>
            </select>
          </div>
        </div>
        <div class="row">
          <div class="col-md-3 mb-3">
            <label class="form-label">Total Income</label>
            <input type="number" class="form-control" formControlName="totalIncome">
          </div>
          <div class="col-md-3 mb-3">
            <label class="form-label">Total Deductions</label>
            <input type="number" class="form-control" formControlName="totalDeductions">
          </div>
          <div class="col-md-3 mb-3">
            <label class="form-label">Taxable Income</label>
            <input type="number" class="form-control" formControlName="taxableIncome">
          </div>
          <div class="col-md-3 mb-3">
            <label class="form-label">Total Tax</label>
            <input type="number" class="form-control" formControlName="totalTax">
          </div>
        </div>
      </div>
    </div>

    <div class="card mb-3" formGroupName="form1040">
      <div class="card-header">Form 1040 Details</div>
      <div class="card-body">
        <div class="row">
          <div class="col-md-4 mb-3">
            <label class="form-label">Full Name</label>
            <input type="text" class="form-control" formControlName="name">
          </div>
          <div class="col-md-4 mb-3">
            <label class="form-label">SSN</label>
            <input type="text" class="form-control" formControlName="ssn">
          </div>
          <div class="col-md-4 mb-3">
            <label class="form-label">Wages (Line 1)</label>
            <input type="number" class="form-control" formControlName="line1_Wages">
          </div>
        </div>
      </div>
    </div>

    <div class="mb-3">
      <button type="submit" class="btn btn-primary" [disabled]="loading">
        {{ loading ? 'Validating...' : 'Submit for Validation' }}
      </button>
    </div>
  </form>

  <div *ngIf="error" class="alert alert-danger">{{ error }}</div>

  <div *ngIf="validationResult" class="mt-4">
    <h3>Validation Results</h3>
    <div [class.alert-success]="validationResult.isValid" [class.alert-danger]="!validationResult.isValid" class="alert">
      <strong>Status:</strong> {{ validationResult.isValid ? 'Valid' : 'Invalid' }}
      <br>
      <strong>Violations:</strong> {{ validationResult.violationCount }}
    </div>

    <ul *ngIf="validationResult.violations.length > 0" class="list-group">
      <li *ngFor="let v of validationResult.violations" class="list-group-item list-group-item-warning">
        <strong>[{{ v.ruleId }}]</strong> {{ v.message }} ({{ v.category }})
      </li>
    </ul>
  </div>
</div>
